  final int _quantityLimit = 100; // maximum quantity limit

  @override
  void buy() {
    if (_quantity >= _quantityLimit) return; // early return if quantity is at limit

    /* some before logic */

    super.buy();
    _quantity++; // increase quantity by 1

    /* some after logic */
  }

  int get quantity => _quantity; // getter for quantity

  @override
